import{_ as t,c as r,o as i,ah as a}from"./chunks/framework.RCw5T9E9.js";const h=JSON.parse('{"title":"Введение","description":"","frontmatter":{"title":"Введение","layout":"doc"},"headers":[],"relativePath":"ru/index.md","filePath":"ru/index.md"}'),o={name:"ru/index.md"};function l(n,e,s,u,p,c){return i(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="введение" tabindex="-1">Введение <a class="header-anchor" href="#введение" aria-label="Permalink to &quot;Введение&quot;">​</a></h1><h2 id="что-такое-vue-inspector" tabindex="-1">Что такое Vue Inspector? <a class="header-anchor" href="#что-такое-vue-inspector" aria-label="Permalink to &quot;Что такое Vue Inspector?&quot;">​</a></h2><p><strong>Vue Inspector</strong> — это инструмент для анализа Vue-приложений в runtime без необходимости доступа к исходному коду, локальной сборке или dev-окружению.</p><p>Расширение позволяет исследовать структуру приложения непосредственно на открытой странице: получать данные о Props, Store, сетевых запросах и внутреннем состоянии компонентов в том виде, в котором они существуют в момент работы приложения.</p><p>Инструмент ориентирован на задачи, где требуется быстро понять текущее состояние frontend-части без подключения дополнительных средств разработки.</p><hr><h2 id="для-чего-использовать-vue-inspector" tabindex="-1">Для чего использовать Vue Inspector? <a class="header-anchor" href="#для-чего-использовать-vue-inspector" aria-label="Permalink to &quot;Для чего использовать Vue Inspector?&quot;">​</a></h2><p>Vue Inspector помогает упростить исследование поведения Vue-приложений в ситуациях, когда стандартных браузерных инструментов недостаточно или требуется более быстрый доступ к runtime-данным.</p><p>Основные возможности:</p><ul><li>Просмотр Props компонентов в реальном времени;</li><li>Анализ полученных и объявленных Props;</li><li>Работа со Store без необходимости ручного поиска в runtime;</li><li>Просмотр сетевых запросов в структурированном виде;</li><li>Быстрый переход к связанным данным внутри приложения;</li><li>Выбор компонентов непосредственно на странице через режим Inspect;</li><li>Фильтрация и локализация нужных данных без ручного обхода DOM-структуры;</li></ul><hr><h2 id="чем-vue-inspector-отличается-от-стандартных-devtools" tabindex="-1">Чем Vue Inspector отличается от стандартных DevTools? <a class="header-anchor" href="#чем-vue-inspector-отличается-от-стандартных-devtools" aria-label="Permalink to &quot;Чем Vue Inspector отличается от стандартных DevTools?&quot;">​</a></h2><p>В отличие от Vue Devtools, Vue Inspector ориентирован не только на локальную разработку, но и на работу с уже запущенными приложениями, где:</p><ul><li>отсутствует доступ к исходному коду;</li><li>недоступна локальная сборка проекта;</li><li>требуется быстро исследовать production или test environment;</li><li>важна работа с runtime-данными без подготовки dev-среды;</li></ul><hr><h2 id="когда-инструмент-особенно-полезен" tabindex="-1">Когда инструмент особенно полезен? <a class="header-anchor" href="#когда-инструмент-особенно-полезен" aria-label="Permalink to &quot;Когда инструмент особенно полезен?&quot;">​</a></h2><p>Vue Inspector может быть полезен в сценариях:</p><ul><li>тестирование frontend-приложений;</li><li>анализ сложных интеграций;</li><li>исследование поведения компонентов;</li><li>локализация проблем в передаче данных;</li><li>проверка реактивного состояния приложения;</li></ul><hr><h2 id="дополнительно" tabindex="-1">Дополнительно <a class="header-anchor" href="#дополнительно" aria-label="Permalink to &quot;Дополнительно&quot;">​</a></h2><p>Проект продолжает развиваться и постепенно расширяет поддержку runtime-анализа для различных frontend-сценариев.</p>',21)])])}const m=t(o,[["render",l]]);export{h as __pageData,m as default};
